// 设置页面边距和页眉页脚距离
var doc = Application.ActiveDocument;
var pageSetup = doc.PageSetup;
pageSetup.TopMargin = 2.54 * 28.35; // 上边距 2.54cm 转磅
pageSetup.BottomMargin = 2.54 * 28.35; // 下边距 2.54cm 转磅
pageSetup.LeftMargin = 3.17 * 28.35; // 左边距 3.17cm 转磅
pageSetup.RightMargin = 3.17 * 28.35; // 右边距 3.17cm 转磅
pageSetup.HeaderDistance = 1.5 * 28.35; // 页眉距离 1.5cm 转磅
pageSetup.FooterDistance = 1.5 * 28.35; // 页脚距离 1.5cm 转磅
return "页面设置完成：上下边距 2.54cm，左右边距 3.17cm，页眉页脚距离 1.5cm";
